/*
# Seed 50 Sneakers Products

Inserts 50 realistic sneaker products with multiple colors, sizes, discount,
COD availability, and ratings. Idempotent via ON CONFLICT (slug) DO NOTHING.
*/

DO $$
DECLARE c_snk uuid;
BEGIN
  SELECT id INTO c_snk FROM public.categories WHERE slug='sneakers';

